import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import {
  createAnalyticsHandlers,
  AnalyticsValidationError,
} from '../../src/routes/analytics.routes.js';
import type { AnalyticsHandlers } from '../../src/routes/analytics.routes.js';

// ---------------------------------------------------------------------------
// Full pipeline integration tests: route handlers → service → data models
// ---------------------------------------------------------------------------

describe('Analytics Pipeline Integration', () => {
  let handlers: AnalyticsHandlers;

  beforeEach(() => {
    const db = new Database();
    const orderRepo = new OrderRepository(db);
    const userRepo = new UserRepository(db);
    const service = new AnalyticsService(orderRepo, userRepo);
    handlers = createAnalyticsHandlers(service);
  });

  // -------------------------------------------------------------------------
  // GET /api/analytics/dashboard — handleGetDashboard
  // -------------------------------------------------------------------------

  describe('handleGetDashboard', () => {
    it('should return a complete dashboard for a valid date range', () => {
      const result = handlers.handleGetDashboard({
        from: '2026-01-01',
        to: '2026-01-31',
      });

      expect(result.dateRange).toEqual({ from: '2026-01-01', to: '2026-01-31' });

      // KPIs present with correct shape
      const kpiKeys = ['totalOrders', 'totalRevenue', 'averageOrderValue', 'totalUsers'] as const;
      for (const key of kpiKeys) {
        const kpi = result.kpis[key];
        expect(kpi).toHaveProperty('name');
        expect(kpi).toHaveProperty('label');
        expect(typeof kpi.value).toBe('number');
        expect(typeof kpi.previousValue).toBe('number');
        expect(typeof kpi.changePercent).toBe('number');
        expect(['up', 'down', 'flat']).toContain(kpi.trend);
      }

      // Arrays present
      expect(Array.isArray(result.orderTimeSeries)).toBe(true);
      expect(Array.isArray(result.revenueTimeSeries)).toBe(true);
      expect(Array.isArray(result.ordersByStatus)).toBe(true);
      expect(Array.isArray(result.topProducts)).toBe(true);
    });

    it('should accept optional granularity parameter', () => {
      const result = handlers.handleGetDashboard({
        from: '2026-01-01',
        to: '2026-12-31',
        granularity: 'month',
      });

      expect(result.dateRange).toEqual({ from: '2026-01-01', to: '2026-12-31' });
      expect(result.kpis).toBeDefined();
    });

    it('should work with a short date range (single day)', () => {
      const result = handlers.handleGetDashboard({
        from: '2026-06-01T00:00:00Z',
        to: '2026-06-01T23:59:59Z',
      });

      expect(result.dateRange.from).toBe('2026-06-01T00:00:00Z');
      expect(result.dateRange.to).toBe('2026-06-01T23:59:59Z');
    });

    it('should work with a long date range (full year)', () => {
      const result = handlers.handleGetDashboard({
        from: '2025-01-01',
        to: '2025-12-31',
      });

      expect(result.dateRange).toEqual({ from: '2025-01-01', to: '2025-12-31' });
    });
  });

  // -------------------------------------------------------------------------
  // GET /api/analytics/metrics/:type — handleGetMetric
  // -------------------------------------------------------------------------

  describe('handleGetMetric', () => {
    const validParams = { from: '2026-01-01', to: '2026-01-31' };

    it.each(['orders', 'revenue', 'users', 'average-order-value'] as const)(
      'should return time series for metric type "%s"',
      (metricType) => {
        const result = handlers.handleGetMetric(metricType, validParams);

        expect(result.metric).toBe(metricType);
        expect(result.dateRange).toEqual({ from: '2026-01-01', to: '2026-01-31' });
        expect(result.granularity).toBeDefined();
        expect(result.summary).toBeDefined();
        expect(result.summary.name).toBe(metricType);
        expect(Array.isArray(result.series)).toBe(true);
      },
    );

    it('should auto-resolve granularity to "hour" for <= 2 day range', () => {
      const result = handlers.handleGetMetric('orders', {
        from: '2026-03-01',
        to: '2026-03-02',
      });
      expect(result.granularity).toBe('hour');
    });

    it('should auto-resolve granularity to "day" for <= 30 day range', () => {
      const result = handlers.handleGetMetric('revenue', {
        from: '2026-03-01',
        to: '2026-03-15',
      });
      expect(result.granularity).toBe('day');
    });

    it('should auto-resolve granularity to "week" for <= 90 day range', () => {
      const result = handlers.handleGetMetric('users', {
        from: '2026-01-01',
        to: '2026-03-15',
      });
      expect(result.granularity).toBe('week');
