      const result = handlers.handleGetMetric('orders', {
        from: '2026-01-01',
        to: '2026-12-31',
      });
      expect(result.granularity).toBe('month');
    });

    it('should use explicit granularity when provided', () => {
      const result = handlers.handleGetMetric('revenue', {
        from: '2026-01-01',
        to: '2026-12-31',
        granularity: 'day',
      });
      expect(result.granularity).toBe('day');
    });

    it('should return a valid MetricSummary in the response', () => {
      const result = handlers.handleGetMetric('orders', validParams);
      const { summary } = result;

      expect(typeof summary.name).toBe('string');
      expect(typeof summary.label).toBe('string');
      expect(typeof summary.value).toBe('number');
      expect(typeof summary.previousValue).toBe('number');
      expect(typeof summary.changePercent).toBe('number');
      expect(['up', 'down', 'flat']).toContain(summary.trend);
    });
  });

  // -------------------------------------------------------------------------
  // GET /api/analytics/top-products — handleGetTopProducts
  // -------------------------------------------------------------------------

  describe('handleGetTopProducts', () => {
    it('should return an array of top products', () => {
      const result = handlers.handleGetTopProducts({
        from: '2026-01-01',
        to: '2026-01-31',
      });

      expect(Array.isArray(result)).toBe(true);
    });

    it('should accept granularity parameter without error', () => {
      const result = handlers.handleGetTopProducts({
        from: '2026-01-01',
        to: '2026-06-30',
        granularity: 'week',
      });

      expect(Array.isArray(result)).toBe(true);
    });
  });

  // -------------------------------------------------------------------------
  // Validation error scenarios
  // -------------------------------------------------------------------------

  describe('Validation Errors', () => {
    describe('missing or invalid "from" parameter', () => {
      it('should throw when "from" is missing', () => {
        expect(() =>
          handlers.handleGetDashboard({ to: '2026-01-31' }),
        ).toThrow(AnalyticsValidationError);
      });

      it('should throw when "from" is not a string', () => {
        expect(() =>
          handlers.handleGetDashboard({ from: 12345, to: '2026-01-31' }),
        ).toThrow(AnalyticsValidationError);
      });

      it('should throw when "from" is an invalid date', () => {
        expect(() =>
          handlers.handleGetDashboard({ from: 'not-a-date', to: '2026-01-31' }),
        ).toThrow(AnalyticsValidationError);
      });
    });

    describe('missing or invalid "to" parameter', () => {
      it('should throw when "to" is missing', () => {
        expect(() =>
          handlers.handleGetDashboard({ from: '2026-01-01' }),
        ).toThrow(AnalyticsValidationError);
      });

      it('should throw when "to" is not a string', () => {
        expect(() =>
          handlers.handleGetDashboard({ from: '2026-01-01', to: null }),
        ).toThrow(AnalyticsValidationError);
      });

      it('should throw when "to" is an invalid date', () => {
        expect(() =>
          handlers.handleGetDashboard({ from: '2026-01-01', to: 'bad' }),
        ).toThrow(AnalyticsValidationError);
      });
    });

    describe('"from" must be before "to"', () => {
      it('should throw when from equals to', () => {
        expect(() =>
          handlers.handleGetDashboard({ from: '2026-01-15', to: '2026-01-15' }),
        ).toThrow(AnalyticsValidationError);
      });

      it('should throw when from is after to', () => {
        expect(() =>
          handlers.handleGetDashboard({ from: '2026-02-01', to: '2026-01-01' }),
        ).toThrow(AnalyticsValidationError);
      });
    });

    describe('invalid granularity', () => {
      it('should throw for unrecognized granularity value', () => {
        expect(() =>
          handlers.handleGetDashboard({
            from: '2026-01-01',
            to: '2026-01-31',
            granularity: 'yearly',
          }),
        ).toThrow(AnalyticsValidationError);
      });

      it('should include the invalid value in the error message', () => {
        expect(() =>
          handlers.handleGetDashboard({
            from: '2026-01-01',
            to: '2026-01-31',
            granularity: 'biweekly',
          }),
        ).toThrow(/biweekly/);
      });
    });

    describe('invalid metric type', () => {
      it('should throw for unrecognized metric type', () => {
        expect(() =>
          handlers.handleGetMetric('clicks', { from: '2026-01-01', to: '2026-01-31' }),
