      });

      it('should include the invalid metric type in the error message', () => {
        expect(() =>
          handlers.handleGetMetric('impressions', { from: '2026-01-01', to: '2026-01-31' }),
        ).toThrow(/impressions/);
      });

      it('should still validate date params before metric type is checked', () => {
        // metric type is validated first in the handler, so this throws about metric type
        expect(() =>
          handlers.handleGetMetric('bad-metric', { from: '2026-01-01', to: '2026-01-31' }),
        ).toThrow(AnalyticsValidationError);
      });
    });

    describe('validation applies to all endpoints', () => {
      it('handleGetMetric validates dates', () => {
        expect(() =>
          handlers.handleGetMetric('orders', { from: 'bad', to: '2026-01-31' }),
