      });

      it('handleGetTopProducts validates granularity', () => {
        expect(() =>
          handlers.handleGetTopProducts({
            from: '2026-01-01',
            to: '2026-01-31',
            granularity: 'quarter',
          }),
        ).toThrow(AnalyticsValidationError);
      });
    });
  });

  // -------------------------------------------------------------------------
  // Cross-cutting: data flows correctly through the full pipeline
  // -------------------------------------------------------------------------

  describe('Pipeline data flow', () => {
    it('should pass date range from handler params through to response', () => {
      const from = '2026-04-01';
      const to = '2026-04-30';

      const dashboard = handlers.handleGetDashboard({ from, to });
      expect(dashboard.dateRange).toEqual({ from, to });

      const metric = handlers.handleGetMetric('revenue', { from, to });
      expect(metric.dateRange).toEqual({ from, to });
    });

    it('should return consistent data between dashboard and metric endpoints', () => {
      const params = { from: '2026-01-01', to: '2026-01-31' };

      const dashboard = handlers.handleGetDashboard(params);
      const ordersMetric = handlers.handleGetMetric('orders', params);

      // Both should have the same date range
      expect(dashboard.dateRange).toEqual(ordersMetric.dateRange);

      // Both use the same granularity resolution logic
      expect(ordersMetric.granularity).toBe('day'); // 30 days → day
    });

    it('top products should be the same subset from dashboard', () => {
      const params = { from: '2026-01-01', to: '2026-01-31' };

      const dashboard = handlers.handleGetDashboard(params);
      const topProducts = handlers.handleGetTopProducts(params);

      expect(topProducts).toEqual(dashboard.topProducts);
    });

    it('should handle ISO timestamps with timezone info end-to-end', () => {
      const result = handlers.handleGetDashboard({
        from: '2026-01-01T00:00:00.000Z',
        to: '2026-01-31T23:59:59.999Z',
      });

      expect(result.dateRange.from).toBe('2026-01-01T00:00:00.000Z');
      expect(result.dateRange.to).toBe('2026-01-31T23:59:59.999Z');
    });

    it('should produce valid AnalyticsValidationError instances', () => {
      try {
        handlers.handleGetDashboard({ from: 'bad', to: '2026-01-31' });
        expect.unreachable('should have thrown');
      } catch (err) {
        expect(err).toBeInstanceOf(AnalyticsValidationError);
        expect(err).toBeInstanceOf(Error);
        expect((err as AnalyticsValidationError).name).toBe('AnalyticsValidationError');
        expect((err as AnalyticsValidationError).message).toContain('from');
      }
    });
  });
